1	import { useState } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Input } from "@/components/ui/input";
5	import { Card } from "@/components/ui/card";
6	import { Label } from "@/components/ui/label";
7	import { Shield, CheckCircle2, Loader2 } from "lucide-react";
8	import { useToast } from "@/hooks/use-toast";
9	
10	interface MFASetupProps {
11	  onComplete: () => void;
12	  onSkip?: () => void;
13	}
14	
15	const MFASetup = ({ onComplete, onSkip }: MFASetupProps) => {
16	  const { toast } = useToast();
17	  const [step, setStep] = useState<"intro" | "qr" | "verify" | "done">("intro");
18	  const [qrCode, setQrCode] = useState("");
19	  const [secret, setSecret] = useState("");
20	  const [factorId, setFactorId] = useState("");
21	  const [verifyCode, setVerifyCode] = useState("");
22	  const [isLoading, setIsLoading] = useState(false);
23	
24	  const setupMFA = async () => {
25	    setIsLoading(true);
26	    try {
27	      const { data, error } = await supabase.auth.mfa.enroll({
28	        factorType: "totp",
29	        friendlyName: "Crevia Authenticator",
30	      });
31	
32	      if (error) throw error;
33	
34	      setQrCode(data.totp.qr_code);
35	      setSecret(data.totp.secret);
36	      setFactorId(data.id);
37	      setStep("qr");
38	    } catch (error: any) {
39	      toast({
40	        title: "Error",
41	        description: error.message,
42	        variant: "destructive",
43	      });
44	    } finally {
45	      setIsLoading(false);
46	    }
47	  };
48	
49	  const verifyMFA = async () => {
50	    if (verifyCode.length !== 6) {
51	      toast({
52	        title: "Invalid code",
53	        description: "Please enter a 6-digit code",
54	        variant: "destructive",
55	      });
56	      return;
57	    }
58	
59	    setIsLoading(true);
60	    try {
61	      const { data: challengeData, error: challengeError } = await supabase.auth.mfa.challenge({
62	        factorId,
63	      });
64	      if (challengeError) throw challengeError;
65	
66	      const { error: verifyError } = await supabase.auth.mfa.verify({
67	        factorId,
68	        challengeId: challengeData.id,
69	        code: verifyCode,
70	      });
71	      if (verifyError) throw verifyError;
72	
73	      setStep("done");
74	      toast({
75	        title: "2FA Enabled!",
76	        description: "Your account is now secured with two-factor authentication.",
77	      });
78	      setTimeout(onComplete, 1500);
79	    } catch (error: any) {
80	      toast({
81	        title: "Invalid code",
82	        description: "The code you entered is incorrect. Please try again.",
83	        variant: "destructive",
84	      });
85	    } finally {
86	      setIsLoading(false);
87	    }
88	  };
89	
90	  return (
91	    <Card className="p-6 max-w-md mx-auto">
92	      {step === "intro" && (
93	        <div className="text-center">
94	          <div className="w-16 h-16 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
95	            <Shield className="w-8 h-8 text-bronze" />
96	          </div>
97	          <h3 className="font-vollkorn text-xl font-bold mb-2">Enable Two-Factor Authentication</h3>
98	          <p className="text-muted-foreground text-sm mb-6">
99	            Add an extra layer of security to your Crevia account using Google Authenticator or Authy.
100	          </p>
101	          <div className="flex flex-col gap-3">
102	            <Button
103	              onClick={setupMFA}
104	              disabled={isLoading}
105	              className="bg-bronze hover:bg-bronze/90 text-background"
106	            >
107	              {isLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Shield className="w-4 h-4 mr-2" />}
108	              Enable 2FA
109	            </Button>
110	            {onSkip && (
111	              <Button variant="ghost" onClick={onSkip} className="text-muted-foreground">
112	                Skip for now
113	              </Button>
114	            )}
115	          </div>
116	        </div>
117	      )}
118	
119	      {step === "qr" && (
120	        <div className="text-center">
121	          <h3 className="font-vollkorn text-xl font-bold mb-2">Scan QR Code</h3>
122	          <p className="text-muted-foreground text-sm mb-4">
123	            Open Google Authenticator or Authy and scan this QR code.
124	          </p>
125	          {qrCode && (
126	            <div className="flex justify-center mb-4">
127	              <img src={qrCode} alt="QR Code" className="w-48 h-48 rounded-lg border border-border" />
128	            </div>
129	          )}
130	          <div className="p-3 bg-muted rounded-lg mb-4">
131	            <p className="text-xs text-muted-foreground mb-1">Or enter this code manually:</p>
132	            <p className="font-mono text-sm font-bold break-all">{secret}</p>
133	          </div>
134	          <Button
135	            onClick={() => setStep("verify")}
136	            className="w-full bg-bronze hover:bg-bronze/90 text-background"
137	          >
138	            I've scanned the code
139	          </Button>
140	        </div>
141	      )}
142	
143	      {step === "verify" && (
144	        <div className="text-center">
145	          <h3 className="font-vollkorn text-xl font-bold mb-2">Verify Setup</h3>
146	          <p className="text-muted-foreground text-sm mb-6">
147	            Enter the 6-digit code from your authenticator app to confirm setup.
148	          </p>
149	          <div className="mb-4">
150	            <Label className="text-sm font-medium mb-2 block">Verification Code</Label>
151	            <Input
152	              value={verifyCode}
153	              onChange={(e) => setVerifyCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
154	              placeholder="000000"
155	              className="text-center text-2xl font-mono tracking-widest h-14"
156	              maxLength={6}
157	              autoFocus
158	            />
159	          </div>
160	          <Button
161	            onClick={verifyMFA}
162	            disabled={isLoading || verifyCode.length !== 6}
163	            className="w-full bg-bronze hover:bg-bronze/90 text-background"
164	          >
165	            {isLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
166	            Verify & Enable
167	          </Button>
168	        </div>
169	      )}
170	
171	      {step === "done" && (
172	        <div className="text-center">
173	          <div className="w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center mx-auto mb-4">
174	            <CheckCircle2 className="w-8 h-8 text-green-500" />
175	          </div>
176	          <h3 className="font-vollkorn text-xl font-bold mb-2">2FA Enabled!</h3>
177	          <p className="text-muted-foreground text-sm">
178	            Your account is now secured with two-factor authentication.
179	          </p>
180	        </div>
181	      )}
182	    </Card>
183	  );
184	};
185	
186	export default MFASetup;
187

1	import { useState } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Input } from "@/components/ui/input";
5	import { Card } from "@/components/ui/card";
6	import { Label } from "@/components/ui/label";
7	import { Shield, Loader2 } from "lucide-react";
8	import { useToast } from "@/hooks/use-toast";
9	import { useNavigate } from "react-router-dom";
10	
11	const MFAVerify = () => {
12	  const { toast } = useToast();
13	  const navigate = useNavigate();
14	  const [code, setCode] = useState("");
15	  const [isLoading, setIsLoading] = useState(false);
16	
17	  const verifyCode = async () => {
18	    if (code.length !== 6) {
19	      toast({
20	        title: "Invalid code",
21	        description: "Please enter a 6-digit code",
22	        variant: "destructive",
23	      });
24	      return;
25	    }
26	
27	    setIsLoading(true);
28	    try {
29	      const { data: factorsData, error: factorsError } = await supabase.auth.mfa.listFactors();
30	      if (factorsError) throw factorsError;
31	
32	      const totpFactor = factorsData.totp[0];
33	      if (!totpFactor) throw new Error("No TOTP factor found");
34	
35	      const { data: challengeData, error: challengeError } = await supabase.auth.mfa.challenge({
36	        factorId: totpFactor.id,
37	      });
38	      if (challengeError) throw challengeError;
39	
40	      const { error: verifyError } = await supabase.auth.mfa.verify({
41	        factorId: totpFactor.id,
42	        challengeId: challengeData.id,
43	        code,
44	      });
45	      if (verifyError) throw verifyError;
46	
47	      toast({
48	        title: "Verified!",
49	        description: "Welcome back to Crevia.",
50	      });
51	      navigate("/kira", { replace: true });
52	
53	    } catch (error: any) {
54	      toast({
55	        title: "Invalid code",
56	        description: "The code you entered is incorrect. Please try again.",
57	        variant: "destructive",
58	      });
59	    } finally {
60	      setIsLoading(false);
61	    }
62	  };
63	
64	  return (
65	    <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
66	      <Card className="w-full max-w-md p-8">
67	        <div className="text-center mb-6">
68	          <div className="w-16 h-16 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
69	            <Shield className="w-8 h-8 text-bronze" />
70	          </div>
71	          <h1 className="font-vollkorn text-2xl font-bold mb-2">Two-Factor Authentication</h1>
72	          <p className="text-muted-foreground text-sm">
73	            Enter the 6-digit code from your authenticator app to continue.
74	          </p>
75	        </div>
76	
77	        <div className="space-y-4">
78	          <div>
79	            <Label className="text-sm font-medium mb-2 block">Verification Code</Label>
80	            <Input
81	              value={code}
82	              onChange={(e) => setCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
83	              placeholder="000000"
84	              className="text-center text-2xl font-mono tracking-widest h-14"
85	              maxLength={6}
86	              autoFocus
87	              onKeyDown={(e) => e.key === 'Enter' && verifyCode()}
88	            />
89	          </div>
90	
91	          <Button
92	            onClick={verifyCode}
93	            disabled={isLoading || code.length !== 6}
94	            className="w-full bg-bronze hover:bg-bronze/90 text-background h-12"
95	          >
96	            {isLoading ? (
97	              <Loader2 className="w-4 h-4 animate-spin mr-2" />
98	            ) : (
99	              <Shield className="w-4 h-4 mr-2" />
100	            )}
101	            Verify & Continue
102	          </Button>
103	
104	          <Button
105	            variant="ghost"
106	            onClick={() => supabase.auth.signOut().then(() => navigate("/auth"))}
107	            className="w-full text-muted-foreground"
108	          >
109	            Sign out and try again
110	          </Button>
111	        </div>
112	      </Card>
113	    </div>
114	  );
115	};
116	
117	export default MFAVerify;
