38	function bufferToBase64url(buffer: ArrayBuffer): string {
39	  const bytes = new Uint8Array(buffer);
40	  let str = "";
41	  for (const b of bytes) str += String.fromCharCode(b);
42	  return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
43	}
44	
45	function base64urlToBuffer(base64url: string): ArrayBuffer {
46	  const base64 = base64url.replace(/-/g, "+").replace(/_/g, "/");
47	  const pad = base64.length % 4 === 0 ? "" : "=".repeat(4 - (base64.length % 4));
48	  const binary = atob(base64 + pad);
49	  const bytes = new Uint8Array(binary.length);
50	  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
51	  return bytes.buffer;
52	}
53	
54	function isWebAuthnSupported(): boolean {
55	  return !!(window.PublicKeyCredential && navigator.credentials);
56	}
57	
58	function isInIframe(): boolean {
59	  try { return window.self !== window.top; } catch { return true; }
60	}
61	
62	async function isPlatformAuthAvailable(): Promise<boolean> {
63	  if (!isWebAuthnSupported()) return false;
64	  if (isInIframe()) return false;
65	  try {
66	    return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
67	  } catch {
68	    return false;
69	  }
70	}
71	
72	async function registerBiometric(userId: string): Promise<string | null> {
73	  const challenge = crypto.getRandomValues(new Uint8Array(32));
74	  const userIdBytes = new TextEncoder().encode(userId);
75	
76	  const credential = (await navigator.credentials.create({
77	    publicKey: {
78	      challenge,
79	      rp: { name: "Crevia", id: window.location.hostname },
80	      user: {
81	        id: userIdBytes,
82	        name: userId,
83	        displayName: "Crevia User",
84	      },
85	      pubKeyCredParams: [
86	        { alg: -7, type: "public-key" },   // ES256
87	        { alg: -257, type: "public-key" },  // RS256
88	      ],
89	      authenticatorSelection: {
90	        authenticatorAttachment: "platform",
91	        userVerification: "required",
92	        residentKey: "preferred",
93	      },
94	      timeout: 60000,
95	      attestation: "none",
96	    },
97	  })) as PublicKeyCredential | null;
98	
99	  if (!credential) return null;
100	  const credId = bufferToBase64url(credential.rawId);
101	  localStorage.setItem(BIOMETRIC_CRED_KEY, credId);
102	  localStorage.setItem(BIOMETRIC_ENABLED_KEY, "true");
103	  return credId;
104	}
105	
106	async function verifyBiometric(): Promise<boolean> {
107	  const storedCredId = localStorage.getItem(BIOMETRIC_CRED_KEY);
108	  if (!storedCredId) return false;
109	
110	  const challenge = crypto.getRandomValues(new Uint8Array(32));
111	  try {
112	    const assertion = (await navigator.credentials.get({
113	      publicKey: {
114	        challenge,
115	        allowCredentials: [
116	          {
117	            id: base64urlToBuffer(storedCredId),
118	            type: "public-key",
119	            transports: ["internal"],
120	          },
121	        ],
122	        userVerification: "required",
123	        timeout: 60000,
124	      },
125	    })) as PublicKeyCredential | null;
126	    return !!assertion;
127	  } catch {
128	    return false;
129	  }
130	}
131	
132	function removeBiometric() {
133	  localStorage.removeItem(BIOMETRIC_CRED_KEY);
134	  localStorage.removeItem(BIOMETRIC_ENABLED_KEY);
135	}
